module RefModule(
    input wire clk,
    input wire load,
    input wire [7:0] data,
    output wire q
);

reg [7:0] register;

always @(posedge clk) begin
    if (load)
        register <= data;
    else
        register <= register >> 1;
end

wire __q_tmp = register[0];
assign q = __q_tmp;

endmodule
